import{_ as a,C as s,o as n,c as i,a3 as l,E as u,w as c,j as t,a as o}from"./chunks/framework.DelMn36m.js";const d="/versions/v0.9.0/screens/routing/midi_output_ports.png",f=JSON.parse('{"title":"Routing","description":"","frontmatter":{},"headers":[],"relativePath":"concepts/routing.md","filePath":"concepts/routing.md"}'),p={name:"concepts/routing.md"};function h(g,e,I,m,v,D){const r=s("ManualRelated");return n(),i("div",null,[e[1]||(e[1]=l('<h1 id="routing" tabindex="-1">Routing <a class="header-anchor" href="#routing" aria-label="Permalink to &quot;Routing&quot;">​</a></h1><p>The S32 can send and receive MIDI on several physical and logical paths.</p><h2 id="physical-ports" tabindex="-1">Physical ports <a class="header-anchor" href="#physical-ports" aria-label="Permalink to &quot;Physical ports&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Port</th><th>Typical use</th></tr></thead><tbody><tr><td><strong>USB</strong></td><td>DAW on computer (MIDI in and out)</td></tr><tr><td><strong>MIDI In / Out 1 / Out 2 / Thru</strong></td><td>Hardware synths and drum machines (TRS + included DIN adapters)</td></tr><tr><td><strong>USB Host</strong></td><td>USB MIDI keyboard or controller plugged into the S32</td></tr></tbody></table><h2 id="virtual-midi-a–d" tabindex="-1">Virtual MIDI A–D <a class="header-anchor" href="#virtual-midi-a–d" aria-label="Permalink to &quot;Virtual MIDI A–D&quot;">​</a></h2><p><strong>Virtual ports</strong> are <strong>internal cables between racks</strong> in the same project.</p><ol><li>Add <strong>MIDI Output</strong> at the end of rack 1.</li><li>Set <strong>Output</strong> to <strong>Virtual A</strong> (or B, C, D).</li><li>In rack 2, add <strong>MIDI Input</strong> (or start chain with devices that accept note input).</li><li>Route rack 2’s <strong>MIDI Input</strong> from <strong>Virtual A</strong>.</li></ol><div class="info custom-block"><p class="custom-block-title">INFO</p><p>Messages go <strong>rack → virtual port → other rack</strong> without looping back to USB unless you choose to.</p></div><p><img src="'+d+'" alt="MIDI Output port options" class="screen"></p><h2 id="usb-host" tabindex="-1">USB Host <a class="header-anchor" href="#usb-host" aria-label="Permalink to &quot;USB Host&quot;">​</a></h2><p>Select <strong>USB Host</strong> as a MIDI Output destination to drive gear connected to the rear <strong>HOST</strong> port — useful for controlling a USB-only module from a rack chain.</p><h2 id="midi-output-device" tabindex="-1">MIDI Output device <a class="header-anchor" href="#midi-output-device" aria-label="Permalink to &quot;MIDI Output device&quot;">​</a></h2><p>Every chain that should produce audible MIDI needs a <strong>MIDI Output</strong> device. Its <strong>Output</strong> parameter picks:</p><ul><li>USB</li><li>MIDI Out 1 / 2</li><li>MIDI Thru</li><li>USB Host</li><li>Virtual A, B, C, D</li></ul><h2 id="thru-vs-processed-out" tabindex="-1">Thru vs processed out <a class="header-anchor" href="#thru-vs-processed-out" aria-label="Permalink to &quot;Thru vs processed out&quot;">​</a></h2><div class="info custom-block"><p class="custom-block-title">INFO</p><ul><li><strong>MIDI Thru</strong> passes input unchanged (hardware-style thru).</li><li><strong>MIDI Output</strong> sends the <strong>processed</strong> chain result.</li></ul></div>',16)),u(r,null,{default:c(()=>[...e[0]||(e[0]=[t("ul",null,[t("li",null,[t("a",{href:"./rack-chains"},"Rack chains"),o(" — Building MIDI device chains")]),t("li",null,[t("a",{href:"./../devices/midi-output"},"MIDI Output device"),o(" — Port selection per rack")]),t("li",null,[t("a",{href:"./../devices/"},"Device reference"),o(" — Every MIDI device type")])],-1)])]),_:1})])}const _=a(p,[["render",h]]);export{f as __pageData,_ as default};
